import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // Create a Scanner object to read input from the console
        Scanner sc = new Scanner(System.in);

        // Read four integers from the user input
        int A = sc.nextInt(); // Represents the initial health of the first entity
        int B = sc.nextInt(); // Represents the attack power of the second entity
        int C = sc.nextInt(); // Represents the initial health of the second entity
        int D = sc.nextInt(); // Represents the attack power of the first entity

        // Check if all input values are within the valid range [1, 100]
        if (1 <= A && A <= 100 && 1 <= B && B <= 100 && 1 <= C && C <= 100 && 1 <= D && D <= 100) {
            // If all values are valid, proceed with the logic
        } else {
            // If any value is out of the valid range, throw an exception with a message
            throw new IllegalArgumentException("不適切な数値です。");
        }

        // Loop until one of the entities' health drops to zero or below
        while (A > 0 && C > 0) {
            // The second entity attacks the first entity, reducing its health
            C -= B;

            // Check if the second entity's health is still above zero
            if (C > 0) {
                // If the second entity is still alive, the first entity attacks back
                A -= D;
            } else {
                // If the second entity's health drops to zero or below, print "Yes" and exit
                System.out.println("Yes");
                return;
            }
        }

        // If the loop exits and the first entity's health is zero or below, print "No"
        System.out.println("No");
    }
}

